import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_basename -> framework -> package_id -> resolvedVersion
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (pname, fw['framework'], pkg['id'])
                lookup[key] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:20s} {c[1]:10s} {c[2]:50s} {c[3]:10s} -> {c[4]}')
else:
    print('  (none)')

print()
print(f'=== UNCHANGED: {len(unchanged)} entries ===')
for u in unchanged:
    print(f'  {u[0]:20s} {u[1]:10s} {u[2]:50s} {u[3]}')
"

